try {
  const body = $input.first().json.body || $input.first().json;
  const file_url = body.file_url || body.fileUrl;
  const file_content = body.file_content || body.fileContent;
  const file_type = (body.file_type || body.fileType || 'pdf').toLowerCase();
  const document_id = body.document_id || body.documentId || ('gda-doc-' + Date.now());
  const metadata = body.metadata || {};

  if (!file_url && !file_content) {
    return [{ json: {
      error: true,
      message: 'file_url or file_content is required. Send file_content (base64) with file_type, or file_url to download from.',
      received_keys: Object.keys(body),
      timestamp: new Date().toISOString()
    }}];
  }

  const valid_namespaces = ['general', 'financial', 'competitive_intel', 'gda-documents'];
  const requested_ns = body.namespace || 'gda-documents';
  const namespace = valid_namespaces.includes(requested_ns) ? requested_ns : 'gda-documents';

  const mimeMap = {
    'pdf':  'application/pdf',
    'docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
    'doc':  'application/msword',
    'xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    'xls':  'application/vnd.ms-excel',
    'pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
    'txt':  'text/plain',
    'csv':  'text/csv'
  };

  return [{ json: {
    file_url: file_url || '',
    file_content: file_content || '',
    has_inline_content: !!file_content,
    file_type,
    document_id,
    namespace,
    mime_type: mimeMap[file_type] || 'application/pdf',
    source: (metadata.source_url || file_url || document_id),
    metadata
  }}];
} catch(e) {
  return [{ json: {
    error: true,
    message: e.message,
    timestamp: new Date().toISOString()
  }}];
}

const item = $input.all()[0];
const validate = $('Validate & Extract').first().json;
const fileType = validate.file_type || 'txt';

let buf;
if (item.binary && item.binary.data) {
  buf = Buffer.from(item.binary.data.data, 'base64');
} else {
  buf = Buffer.from('');
}

let text = '';

if (fileType === 'txt' || fileType === 'csv' || fileType === 'md') {
  text = buf.toString('utf-8');

} else if (fileType === 'pdf') {
  const raw = buf.toString('binary');
  const blocks = [];
  const parenRe = /\(([^)\\]|\\[\s\S]){1,500}\)/g;
  let m;
  while ((m = parenRe.exec(raw)) !== null) {
    const s = m[0].slice(1,-1)
      .replace(/\\n/g,'\n').replace(/\\r/g,'\n').replace(/\\t/g,' ')
      .replace(/\\\(/g,'(').replace(/\\\)/g,')').replace(/\\\\/g,'\\')
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F-\x9F]/g,' ').trim();
    const r = (s.match(/[\x20-\x7E]/g)||[]).length / Math.max(s.length,1);
    if (s.length > 3 && r > 0.6) blocks.push(s);
  }
  const hexRe = /<([0-9A-Fa-f]{2})+>/g;
  while ((m = hexRe.exec(raw)) !== null) {
    const hex = m[0].slice(1,-1);
    let hs = '';
    for (let i=0;i<hex.length;i+=2) {
      const c = parseInt(hex.slice(i,i+2),16);
      if (c>=32&&c<127) hs+=String.fromCharCode(c);
      else if (c===10||c===13) hs+=' ';
    }
    if (hs.trim().length>3) blocks.push(hs.trim());
  }
  text = blocks.join(' ').replace(/\s+/g,' ').trim();

} else if (fileType === 'docx' || fileType === 'doc') {
  const raw = buf.toString('binary');
  const wt = /<w:t[^>]*>([^<]*)<\/w:t>/g;
  const parts = [];
  let m;
  while ((m = wt.exec(raw)) !== null) {
    if (m[1].trim()) parts.push(m[1].trim());
  }
  if (parts.length > 0) {
    text = parts.join(' ');
  } else {
    text = raw.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
    text = text.split('').filter(c=>c.charCodeAt(0)>=32&&c.charCodeAt(0)<127||c==='\n').join('');
  }

} else if (fileType === 'xlsx' || fileType === 'xls') {
  const raw = buf.toString('binary');
  const si = /<si[^>]*>[\s\S]*?<\/si>/g;
  const parts = [];
  let s;
  while ((s = si.exec(raw)) !== null) {
    const t2 = /<t[^>]*>([^<]*)<\/t>/g;
    let t;
    while ((t = t2.exec(s[0])) !== null) {
      if (t[1].trim()) parts.push(t[1].trim());
    }
  }
  const vr = /<v>([^<]+)<\/v>/g;
  let v;
  while ((v = vr.exec(raw)) !== null) {
    const val = v[1].trim();
    if (val && isNaN(Number(val))) parts.push(val);
  }
  text = parts.join(' ');

} else if (fileType === 'pptx') {
  const raw = buf.toString('binary');
  const ar = /<a:t[^>]*>([^<]*)<\/a:t>/g;
  const parts = [];
  let m;
  while ((m = ar.exec(raw)) !== null) {
    if (m[1].trim()) parts.push(m[1].trim());
  }
  text = parts.join(' ');

} else {
  text = buf.toString('utf-8').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g,' ');
}

if (!text || text.length < 20) {
  text = buf.toString('latin1').replace(/[^\x20-\x7E\n\r\t]/g,' ').replace(/\s+/g,' ').trim();
}

const chunkSize = 1500;
const overlap = 200;
const chunks = [];
let i = 0;
while (i < text.length) {
  const chunk = text.substring(i, i+chunkSize).trim();
  if (chunk.length > 50) chunks.push(chunk);
  i += chunkSize - overlap;
  if (i + chunkSize > text.length && i < text.length) {
    const last = text.substring(i).trim();
    if (last.length > 50) chunks.push(last);
    break;
  }
}
if (chunks.length === 0 && text.length > 0) chunks.push(text.substring(0,chunkSize));

console.log('text_len:'+text.length+' chunks:'+chunks.length+' type:'+fileType);

return chunks.map((chunk,idx) => ({
  json: {
    text: chunk,
    chunk_index: idx,
    total_chunks: chunks.length,
    document_id: validate.document_id,
    namespace: validate.namespace,
    file_type: fileType,
    source: validate.source,
    metadata: validate.metadata || {},
    extracted_text_length: text.length
  }
}));

const validateResult = $('Validate & Extract').first().json;
if (validateResult.error) {
  return [{ json: {
    success: false,
    error: true,
    message: validateResult.message,
    received_keys: validateResult.received_keys || [],
    timestamp: new Date().toISOString()
  }}];
}
const doc_id = validateResult.document_id;
const file_type = validateResult.file_type;
const namespace = validateResult.namespace;
let upsertItems = [];
try { upsertItems = $('Upsert to Pinecone').all() || []; } catch(e) { upsertItems = []; }
const chunks_succeeded = upsertItems.filter(i => (i.json?.upsertedCount || 0) > 0).length;
const chunks_failed = upsertItems.filter(i => !i.json?.upsertedCount).length;
return [{ json: {
  success: chunks_succeeded > 0,
  document_id: doc_id,
  file_type: file_type,
  namespace: namespace,
  chunks_succeeded: chunks_succeeded,
  chunks_failed: chunks_failed,
  message: chunks_succeeded > 0
    ? 'Document ingested: ' + chunks_succeeded + ' chunks stored in Pinecone namespace ' + namespace
    : 'WARNING: Document accepted but 0 chunks stored in Pinecone',
  timestamp: new Date().toISOString()
}}];

const validate = $('Validate & Extract').first().json;
const content_b64 = validate.file_content;
let buf;
try {
  buf = Buffer.from(content_b64, 'base64');
  if (buf.length < 10) buf = Buffer.from(content_b64, 'utf-8');
} catch(e) {
  buf = Buffer.from(content_b64, 'utf-8');
}
const mimeType = validate.mime_type || 'text/plain';
const fileName = validate.document_id + '.' + (validate.file_type || 'txt');
const base64 = buf.toString('base64');
return [{
  json: validate,
  binary: {
    data: {
      data: base64,
      mimeType: mimeType,
      fileName: fileName,
      fileExtension: validate.file_type || 'txt'
    }
  }
}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

